int main() {
    Employee emp("Alice", 101);
    Manager mgr("Bob", 201, "Sales");

    std::cout << "--- Direct Calls ---" << std::endl;
    emp.displayInfo();
    mgr.displayInfo();
    std::cout << std::endl;

    std::cout << "--- Polymorphic Calls (via base pointer) ---" << std::endl;
    Employee* e1 = new Employee("Charlie", 301);
    Employee* e2 = new Manager("David", 401, "Marketing");

    e1->displayInfo();
    e2->displayInfo();

    delete e1;
    delete e2;
    std::cout << std::endl;

    return 0;
}
